const body = $input.first().json.body ?? $input.first().json;

// Ignora se não for mensagem válida
if (!body.data || !body.data.message) {
  return [];
}

const message = body.data;
const isFromMe = message.key?.fromMe === true;
const isGroup = message.key?.remoteJid?.includes('@g.us');
const isStatus = message.key?.remoteJid === 'status@broadcast';

if (isFromMe || isGroup || isStatus) {
  return [];
}

// Extrai dados relevantes
const telefone = message.key.remoteJid.replace('@s.whatsapp.net', '');
const messageType = message.messageType || '';
const isAudio = messageType === 'audioMessage';
const texto = message.message?.conversation
  || message.message?.extendedTextMessage?.text
  || '';
const pushName = message.pushName || '';

// Permite áudio mesmo sem texto
if (!texto.trim() && !isAudio) {
  return [];
}

return [{
  json: {
    telefone,
    texto,
    pushName,
    messageId: message.key.id,
    messageType,
    timestamp: new Date().toISOString()
  }
}];

return $input.all().map(item => {
  const doc = item.json.document;
  if (!doc) return null; // ignora itens sem documento

  const fields = doc.fields || {};

  const parseField = (field) => {
    if (!field || typeof field !== 'object') return field;

    const valueKey = Object.keys(field).find(k => k.endsWith('Value'));
    if (valueKey) return field[valueKey];

    if (field.mapValue) {
      const mapFields = field.mapValue.fields || {};
      const obj = {};
      for (const [k, v] of Object.entries(mapFields)) {
        obj[k] = parseField(v);
      }
      return obj;
    }

    if (field.arrayValue) {
      const values = field.arrayValue.values || [];
      return values.map(parseField);
    }

    return field;
  };

  const parsedData = {};
  for (const [key, value] of Object.entries(fields)) {
    parsedData[key] = parseField(value);
  }

  return {
    json: {
      id: doc.name?.split('/').pop() || null,
      ...parsedData
    }
  };
}).filter(x => x !== null); // remove itens nulos

const tsRaw = $('Formata JSON').first().json.time_agent_off

if (!tsRaw || tsRaw === '' || tsRaw === null || tsRaw === undefined) {
  return [{ json: { hoursPassed: 999 } }];
}

let tsMillis = null;
let valid = true;

if (typeof tsRaw === 'number') {
  tsMillis = tsRaw < 1e12 ? tsRaw * 1000 : tsRaw;
} else if (typeof tsRaw === 'string') {
  const digitsOnly = /^\d+$/;
  if (digitsOnly.test(tsRaw)) {
    const n = Number(tsRaw);
    tsMillis = n < 1e12 ? n * 1000 : n;
  } else {
    const parsed = Date.parse(tsRaw);
    if (Number.isNaN(parsed)) {
      valid = false;
    } else {
      tsMillis = parsed;
    }
  }
} else {
  valid = false;
}

let hoursPassed = 999;
if (valid && tsMillis) {
  const now = Date.now();
  hoursPassed = (now - tsMillis) / (1000 * 60 * 60);
}

return [{ json: { hoursPassed } }];

const ultima_mensagem_da_fila = $input.last();
const mensagem_do_workflow = $('Enfileirar mensagem.').first();

if (ultima_mensagem_da_fila.json.id_mensagem !== mensagem_do_workflow.json.id_mensagem) {
  // Mensagem encavalada, para o workflow
  return [];
}

const texto = $input
  .all()
  .map((item) => item.json.message ?? '')
  .join('\n');

return [
  {
    json: {
      texto,
    },
  },
];

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');

return [{
  json: {
    audioBase64: base64
  }
}];
